-- {"operators": "INNER_JOIN,AGGREGATE", "complexity": "medium", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "DISTRICT,CUSTOMER", "delta": true}
SELECT d.D_W_ID, d.D_ID, CONCAT(d.D_NAME, '/', d.D_ZIP) AS id_label, COUNT(c.C_ID) AS custs, SUM(LENGTH(c.C_LAST)) AS total_name_chars FROM d_DISTRICT d JOIN d_CUSTOMER c ON d.D_W_ID = c.C_W_ID AND d.D_ID = c.C_D_ID GROUP BY d.D_W_ID, d.D_ID, CONCAT(d.D_NAME, '/', d.D_ZIP);
